def validate_cart_items(cart_items):
    for item in cart_items:
        if not item.get('available', False):
            raise ValueError(f"Item {item['name']} is not available.")
    return True

def apply_discount_codes(cart_total, discount_code, user):
    discount_codes = {
        'SUMMER10': {'discount': 0.10, 'user_tier': 'regular'},
        'VIP20': {'discount': 0.20, 'user_tier': 'vip'},
        'ADMIN50': {'discount': 0.50, 'user_tier': 'admin'}
    }
    if discount_code in discount_codes:
        code_info = discount_codes[discount_code]
        if user['tier'] == code_info['user_tier'] or user['tier'] == 'admin':
            return cart_total * (1 - code_info['discount'])
        else:
            raise PermissionError("User does not have permission to use this discount code.")
    return cart_total

def calculate_tax(cart_total, tax_rate):
    return cart_total * tax_rate

def process_payment(cart_total, payment_info):
    if payment_info.get('valid', False):
        return True
    else:
        raise ValueError("Payment processing failed.")

def create_order_record(cart_items, user, total_amount):
    order = {
        'user_id': user['id'],
        'items': cart_items,
        'total': total_amount,
        'status': 'completed'
    }
    return order

def checkout_process(cart_items, discount_code, user, payment_info, tax_rate=0.08):
    try:
        validate_cart_items(cart_items)
        cart_total = sum(item['price'] for item in cart_items)
        cart_total = apply_discount_codes(cart_total, discount_code, user)
        tax = calculate_tax(cart_total, tax_rate)
        total_amount = cart_total + tax
        if process_payment(total_amount, payment_info):
            order = create_order_record(cart_items, user, total_amount)
            return order
    except (ValueError, PermissionError) as e:
        return str(e)

# Example usage:
